func tagBadgeClass(tag models.TaskTag) string {
	switch tag {
	case models.TagFeature:
		return "badge-success"
	case models.TagBug:
		return "badge-error"
	default:
		return "badge-ghost"
	}
}

func truncatePrompt(prompt string, maxLen int) string {
	if len(prompt) <= maxLen {
		return prompt
	}
	return prompt[:maxLen] + "..."
}

func scheduleLabel(s *models.Schedule) string {
	switch s.RepeatType {
	case models.RepeatOnce:
		return "once"
	case models.RepeatSeconds:
		return fmt.Sprintf("every %ds", s.RepeatInterval)
	case models.RepeatMinutes:
		return fmt.Sprintf("every %dm", s.RepeatInterval)
	case models.RepeatHours:
		return fmt.Sprintf("every %dh", s.RepeatInterval)
	case models.RepeatDaily:
		if s.RepeatInterval == 1 {
			return "daily"
		}
		return fmt.Sprintf("every %d days", s.RepeatInterval)
	case models.RepeatWeekly:
		if s.RepeatInterval == 1 {
			return "weekly"
		}
		return fmt.Sprintf("every %d weeks", s.RepeatInterval)
	case models.RepeatMonthly:
		if s.RepeatInterval == 1 {
			return "monthly"
		}
		return fmt.Sprintf("every %d months", s.RepeatInterval)
	default:
		return string(s.RepeatType)
	}
}

